        day >= "2020-01-06" & day < "2020-02-29",
        "Jan_Feb",
        ifelse(
          day >= "2020-02-29" & day < "2020-03-25",
          "Early_March",
          ifelse(
            day >= "2020-03-25" &
              day < "2020-04-28",
            "Lockdown",
             ifelse(
            day >= "2017-08-27" &
            day <= "2018-07-10",
            "Wave_9",
            "Post_Lockdown"
            )))))) )%>%
  dplyr::mutate(condition = forcats::fct_relevel(condition, ord_dates_class)) %>%
  arrange(day)

